const fs = require('fs');
const path = require('path');
const vaultPath = 'E:\\数字\\vault\\数字分身';
const pendingDir = path.join(vaultPath, '待确认');
const archiveDir = path.join(vaultPath, '对话存档');
const deletedDir = path.join(vaultPath, '对话删除');
if (!fs.existsSync(archiveDir)) fs.mkdirSync(archiveDir, { recursive: true });
if (!fs.existsSync(deletedDir)) fs.mkdirSync(deletedDir, { recursive: true });

function sanitizeFileName(name) { return name.replace(/[<>:"\/|?*]/g, '-'); }

let files = [];
try { files = fs.readdirSync(pendingDir); } catch(e) { return [{ json: { done: 0, cancelled: 0, errors: [] } }]; }

let done = 0, cancelled = 0;
let errors = [];

for (const f of files) {
  if (!f.endsWith('.md')) continue;
  const filePath = path.join(pendingDir, f);
  let content = '';
  try { content = fs.readFileSync(filePath, 'utf-8'); } catch(e) { continue; }

  const fmMatch = content.match(/^---\r?\n([\s\S]*?)\r?\n---/);
  const frontmatter = fmMatch ? fmMatch[1] : '';
  if (!frontmatter) continue;
  const isDone = /status:\s*done/i.test(frontmatter) || /status:\s*\r?\n\s*-\s*done/i.test(frontmatter);
  const isCancelled = /status:\s*cancelled/i.test(frontmatter) || /status:\s*\r?\n\s*-\s*cancelled/i.test(frontmatter);
  if (!isDone && !isCancelled) continue;

  try {
    if (isDone) {
      const now = new Date();
      const timeStr = now.getFullYear() + '-' +
        String(now.getMonth()+1).padStart(2,'0') + '-' +
        String(now.getDate()).padStart(2,'0') + '-' +
        String(now.getHours()).padStart(2,'0') +
        String(now.getMinutes()).padStart(2,'0') +
        String(now.getSeconds()).padStart(2,'0');
      const titleMatch = frontmatter.match(/archive_title:\s*"?([^"\n\r]+)"?/);
      let archiveTitle = titleMatch ? titleMatch[1].trim().replace(/^"|"$/g,'') : '';
      if (!archiveTitle || archiveTitle === '""') {
        const fallbackTitle = frontmatter.match(/title:\s*"?([^"\n\r]+)"?/);
        archiveTitle = fallbackTitle ? fallbackTitle[1].trim().replace(/^"|"$/g,'') : '';
      }
      archiveTitle = sanitizeFileName(archiveTitle);
      const suffix = archiveTitle ? '-' + archiveTitle : '';
      const archiveFileName = '[对话存档] ' + timeStr + suffix + '.md';
      let newContent = content
        .replace(/type:\s*待确认/, 'type: 对话存档')
        .replace(/status:\s*done/i, 'status: archived').replace(/status:\s*\r?\n\s*-\s*done/i, 'status: archived');
      fs.writeFileSync(path.join(archiveDir, archiveFileName), newContent, 'utf-8');
      fs.unlinkSync(filePath);
      done++;
    } else {
      const now2 = new Date();
      const timeStr2 = now2.getFullYear() + '-' +
        String(now2.getMonth()+1).padStart(2,'0') + '-' +
        String(now2.getDate()).padStart(2,'0') + '-' +
        String(now2.getHours()).padStart(2,'0') +
        String(now2.getMinutes()).padStart(2,'0') +
        String(now2.getSeconds()).padStart(2,'0');
      const titleMatch2 = frontmatter.match(/archive_title:\s*"?([^"\n\r]+)"?/);
      let archiveTitle2 = titleMatch2 ? titleMatch2[1].trim().replace(/^"|"$/g,'') : '';
      if (!archiveTitle2 || archiveTitle2 === '""') {
        const fallbackTitle2 = frontmatter.match(/title:\s*"?([^"\n\r]+)"?/);
        archiveTitle2 = fallbackTitle2 ? fallbackTitle2[1].trim().replace(/^"|"$/g,'') : '';
      }
      archiveTitle2 = sanitizeFileName(archiveTitle2);
      const suffix2 = archiveTitle2 ? '-' + archiveTitle2 : '';
      const deletedFileName = '[对话删除] ' + timeStr2 + suffix2 + '.md';
      let newContent = content
        .replace(/type:\s*待确认/, 'type: 对话删除')
        .replace(/status:\s*cancelled/i, 'status: deleted').replace(/status:\s*\r?\n\s*-\s*cancelled/i, 'status: deleted');
      fs.writeFileSync(path.join(deletedDir, deletedFileName), newContent, 'utf-8');
      fs.unlinkSync(filePath);
      cancelled++;
    }
  } catch(e) {
    errors.push(f + ': ' + String(e).slice(0, 100));
  }
}

return [{ json: { done: done, cancelled: cancelled, errors: errors } }];
